"""Fetch a URL and return status code + body with automatic JSON detection."""

import requests
from typing import Any, Dict


def fetch_url(input_data: dict) -> dict:
    """Fetch a URL and return status code + body. Auto-detects JSON responses.

    Parameters:
        url (str): The URL to fetch
        method (str, optional): HTTP method, default "GET"
        headers (dict, optional): Custom headers
        timeout (int, optional): Timeout in seconds, default 15

    Returns:
        dict with keys: status_code, content_type, data (if JSON), text (if not JSON),
        url, and optionally error.
    """
    url = input_data.get("url")
    if not url or not isinstance(url, str):
        return {"error": "Missing or invalid required parameter: url"}

    method = input_data.get("method", "GET").upper()
    headers = input_data.get("headers") or {}
    timeout = input_data.get("timeout", 15)

    if not isinstance(headers, dict):
        return {"error": "Parameter 'headers' must be a dict"}

    if not isinstance(timeout, (int, float)) or timeout <= 0:
        return {"error": "Parameter 'timeout' must be a positive number"}

    if method not in ("GET", "POST", "PUT", "DELETE", "PATCH", "HEAD", "OPTIONS"):
        return {"error": f"Unsupported HTTP method: {method}"}

    try:
        response = requests.request(
            method=method,
            url=url,
            headers=headers,
            timeout=timeout,
        )
    except requests.exceptions.Timeout:
        return {"error": f"Request timed out after {timeout} seconds", "url": url}
    except requests.exceptions.ConnectionError as exc:
        return {"error": f"Connection error: {str(exc)}", "url": url}
    except requests.exceptions.RequestException as exc:
        return {"error": f"Request failed: {str(exc)}", "url": url}

    content_type = response.headers.get("Content-Type", "")
    result: Dict[str, Any] = {
        "status_code": response.status_code,
        "content_type": content_type,
        "url": url,
    }

    if "application/json" in content_type:
        try:
            result["data"] = response.json()
        except ValueError:
            result["text"] = response.text
            result["error"] = "Content-Type indicated JSON but body could not be parsed"
    else:
        result["text"] = response.text

    return result

"""Fetch a URL and extract clean readable text from the HTML."""

import re

import requests
from bs4 import BeautifulSoup
from typing import Any, Dict


def scrape_page_text(input_data: dict) -> dict:
    """Fetch a URL and extract clean readable text from the HTML.

    Parameters:
        url (str): URL to scrape
        selector (str, optional): CSS selector to target specific elements
        max_length (int, optional): Max characters to return, default 10000

    Returns:
        dict with keys: text, title, char_count, truncated, url, and optionally error.
    """
    url = input_data.get("url")
    if not url or not isinstance(url, str):
        return {"error": "Missing or invalid required parameter: url"}

    selector = input_data.get("selector")
    max_length = input_data.get("max_length", 10000)

    if not isinstance(max_length, int) or max_length <= 0:
        return {"error": "Parameter 'max_length' must be a positive integer"}

    try:
        response = requests.get(url, timeout=15, headers={"User-Agent": "Mozilla/5.0"})
        response.raise_for_status()
    except requests.exceptions.Timeout:
        return {"error": "Request timed out", "url": url}
    except requests.exceptions.ConnectionError as exc:
        return {"error": f"Connection error: {str(exc)}", "url": url}
    except requests.exceptions.HTTPError as exc:
        return {"error": f"HTTP error {response.status_code}: {str(exc)}", "url": url}
    except requests.exceptions.RequestException as exc:
        return {"error": f"Request failed: {str(exc)}", "url": url}

    try:
        soup = BeautifulSoup(response.text, "html.parser")
    except Exception as exc:
        return {"error": f"Failed to parse HTML: {str(exc)}", "url": url}

    # Extract title
    title_tag = soup.find("title")
    title = title_tag.get_text(strip=True) if title_tag else ""

    # Remove non-content tags
    for tag_name in ("script", "style", "nav", "footer", "header", "noscript", "svg"):
        for tag in soup.find_all(tag_name):
            tag.decompose()

    # Scope to selector if provided
    if selector:
        elements = soup.select(selector)
        if not elements:
            return {
                "text": "",
                "title": title,
                "char_count": 0,
                "truncated": False,
                "url": url,
                "error": f"No elements matched selector: {selector}",
            }
        text_parts = [el.get_text(separator="\n", strip=True) for el in elements]
        raw_text = "\n\n".join(text_parts)
    else:
        body = soup.find("body")
        target = body if body else soup
        raw_text = target.get_text(separator="\n", strip=True)

    # Clean up whitespace: collapse multiple blank lines and spaces
    text = re.sub(r"[ \t]+", " ", raw_text)
    text = re.sub(r"\n{3,}", "\n\n", text)
    text = text.strip()

    truncated = len(text) > max_length
    if truncated:
        text = text[:max_length]

    return {
        "text": text,
        "title": title,
        "char_count": len(text),
        "truncated": truncated,
        "url": url,
    }

"""Call a REST API endpoint and return parsed JSON response."""

import requests
from typing import Any, Dict


def fetch_json_api(input_data: dict) -> dict:
    """Call a REST API endpoint and return parsed JSON response.

    Parameters:
        url (str): API endpoint URL
        method (str, optional): GET/POST/PUT/DELETE, default "GET"
        headers (dict, optional): Request headers
        params (dict, optional): Query parameters
        body (dict, optional): JSON request body (for POST/PUT)
        timeout (int, optional): Timeout in seconds, default 15

    Returns:
        dict with keys: status_code, data, headers (subset), and optionally error.
    """
    url = input_data.get("url")
    if not url or not isinstance(url, str):
        return {"error": "Missing or invalid required parameter: url"}

    method = input_data.get("method", "GET").upper()
    custom_headers = input_data.get("headers") or {}
    params = input_data.get("params") or {}
    body = input_data.get("body")
    timeout = input_data.get("timeout", 15)

    if not isinstance(custom_headers, dict):
        return {"error": "Parameter 'headers' must be a dict"}
    if not isinstance(params, dict):
        return {"error": "Parameter 'params' must be a dict"}
    if not isinstance(timeout, (int, float)) or timeout <= 0:
        return {"error": "Parameter 'timeout' must be a positive number"}
    if method not in ("GET", "POST", "PUT", "DELETE", "PATCH"):
        return {"error": f"Unsupported HTTP method: {method}"}

    headers: Dict[str, str] = {"Content-Type": "application/json", "Accept": "application/json"}
    headers.update(custom_headers)

    request_kwargs: Dict[str, Any] = {
        "method": method,
        "url": url,
        "headers": headers,
        "params": params if params else None,
        "timeout": timeout,
    }

    if body is not None and method in ("POST", "PUT", "PATCH"):
        request_kwargs["json"] = body

    try:
        response = requests.request(**request_kwargs)
    except requests.exceptions.Timeout:
        return {"error": f"Request timed out after {timeout} seconds", "status_code": None, "data": None, "headers": {}}
    except requests.exceptions.ConnectionError as exc:
        return {"error": f"Connection error: {str(exc)}", "status_code": None, "data": None, "headers": {}}
    except requests.exceptions.RequestException as exc:
        return {"error": f"Request failed: {str(exc)}", "status_code": None, "data": None, "headers": {}}

    # Extract a useful subset of response headers
    header_keys = ("Content-Type", "Content-Length", "Date", "Server",
                   "X-Request-Id", "X-RateLimit-Limit", "X-RateLimit-Remaining",
                   "Retry-After", "ETag", "Cache-Control", "Location")
    response_headers = {
        k: response.headers[k]
        for k in header_keys
        if k in response.headers
    }

    result: Dict[str, Any] = {
        "status_code": response.status_code,
        "headers": response_headers,
    }

    try:
        result["data"] = response.json()
    except ValueError:
        result["data"] = None
        result["error"] = (
            "Response body is not valid JSON. "
            f"Content-Type: {response.headers.get('Content-Type', 'unknown')}"
        )

    return result

"""Fetch a URL and extract all hyperlinks with their labels."""

import re
from urllib.parse import urljoin, urlparse

import requests
from bs4 import BeautifulSoup
from typing import Any, Dict, List


def scrape_links(input_data: dict) -> dict:
    """Fetch a URL and extract all hyperlinks with their labels.

    Parameters:
        url (str): URL to scrape
        filter_pattern (str, optional): Regex to filter link URLs
        absolute_only (bool, optional): Only return absolute URLs, default true
        selector (str, optional): CSS selector to scope link extraction

    Returns:
        dict with keys: links (list of {url, text, title?}), count, source_url,
        and optionally error.
    """
    url = input_data.get("url")
    if not url or not isinstance(url, str):
        return {"error": "Missing or invalid required parameter: url"}

    filter_pattern = input_data.get("filter_pattern")
    absolute_only = input_data.get("absolute_only", True)
    selector = input_data.get("selector")

    # Validate filter_pattern if provided
    compiled_filter = None
    if filter_pattern:
        try:
            compiled_filter = re.compile(filter_pattern)
        except re.error as exc:
            return {"error": f"Invalid filter_pattern regex: {str(exc)}"}

    try:
        response = requests.get(url, timeout=15, headers={"User-Agent": "Mozilla/5.0"})
        response.raise_for_status()
    except requests.exceptions.Timeout:
        return {"error": "Request timed out", "source_url": url, "links": [], "count": 0}
    except requests.exceptions.ConnectionError as exc:
        return {"error": f"Connection error: {str(exc)}", "source_url": url, "links": [], "count": 0}
    except requests.exceptions.HTTPError as exc:
        return {"error": f"HTTP error: {str(exc)}", "source_url": url, "links": [], "count": 0}
    except requests.exceptions.RequestException as exc:
        return {"error": f"Request failed: {str(exc)}", "source_url": url, "links": [], "count": 0}

    try:
        soup = BeautifulSoup(response.text, "html.parser")
    except Exception as exc:
        return {"error": f"Failed to parse HTML: {str(exc)}", "source_url": url, "links": [], "count": 0}

    # Scope to selector if provided
    if selector:
        containers = soup.select(selector)
        anchors: List[Any] = []
        for container in containers:
            anchors.extend(container.find_all("a", href=True))
    else:
        anchors = soup.find_all("a", href=True)

    links: List[Dict[str, str]] = []
    seen_urls = set()

    for anchor in anchors:
        href = anchor["href"].strip()

        # Skip fragment-only and javascript links
        if href.startswith("#") or href.startswith("javascript:") or href.startswith("mailto:"):
            continue

        # Resolve relative URLs
        resolved_url = urljoin(url, href)

        # Filter: absolute only
        if absolute_only:
            parsed = urlparse(resolved_url)
            if not parsed.scheme or not parsed.netloc:
                continue

        # Deduplicate
        if resolved_url in seen_urls:
            continue
        seen_urls.add(resolved_url)

        # Apply filter pattern
        if compiled_filter and not compiled_filter.search(resolved_url):
            continue

        link_text = anchor.get_text(strip=True)
        link_entry: Dict[str, str] = {
            "url": resolved_url,
            "text": link_text,
        }

        title_attr = anchor.get("title")
        if title_attr:
            link_entry["title"] = title_attr.strip()

        links.append(link_entry)

    return {
        "links": links,
        "count": len(links),
        "source_url": url,
    }

"""Keyword search tool: find keywords in text with surrounding context snippets."""

import re
from typing import Any, Dict, List


def keyword_search(input_data: dict) -> dict:
    """Search text for keywords and return surrounding context snippets.

    Parameters:
        text (str): Text to search.
        keywords (list[str]): Keywords to find.
        context_chars (int, optional): Characters of context around each match, default 100.
        case_sensitive (bool, optional): Default false.
        max_results (int, optional): Max results per keyword, default 10.

    Returns:
        dict with results, total_matches, keywords_found, keywords_missing, and optional error.
    """
    try:
        # --- Validate inputs ---------------------------------------------------
        text = input_data.get("text")
        if not isinstance(text, str):
            return {"results": [], "total_matches": 0, "keywords_found": [],
                    "keywords_missing": [], "error": "Parameter 'text' is required and must be a string."}

        keywords = input_data.get("keywords")
        if not isinstance(keywords, list) or len(keywords) == 0:
            return {"results": [], "total_matches": 0, "keywords_found": [],
                    "keywords_missing": [], "error": "Parameter 'keywords' is required and must be a non-empty list of strings."}

        context_chars = int(input_data.get("context_chars", 100))
        if context_chars < 0:
            context_chars = 0

        case_sensitive = bool(input_data.get("case_sensitive", False))
        max_results = int(input_data.get("max_results", 10))
        if max_results < 1:
            max_results = 1

        # --- Search ------------------------------------------------------------
        results: List[Dict[str, Any]] = []
        keywords_found: List[str] = []
        keywords_missing: List[str] = []

        for keyword in keywords:
            if not isinstance(keyword, str) or keyword == "":
                continue

            flags = 0 if case_sensitive else re.IGNORECASE
            pattern = re.escape(keyword)
            matches = list(re.finditer(pattern, text, flags))

            if not matches:
                keywords_missing.append(keyword)
                continue

            keywords_found.append(keyword)

            for match in matches[:max_results]:
                start = match.start()
                end = match.end()

                snippet_start = max(0, start - context_chars)
                snippet_end = min(len(text), end + context_chars)

                snippet = text[snippet_start:snippet_end]

                # Add ellipsis indicators when the snippet is truncated
                if snippet_start > 0:
                    snippet = "..." + snippet
                if snippet_end < len(text):
                    snippet = snippet + "..."

                results.append({
                    "keyword": keyword,
                    "snippet": snippet,
                    "position": start,
                })

        return {
            "results": results,
            "total_matches": len(results),
            "keywords_found": keywords_found,
            "keywords_missing": keywords_missing,
        }

    except Exception as exc:
        return {
            "results": [],
            "total_matches": 0,
            "keywords_found": [],
            "keywords_missing": [],
            "error": f"Unexpected error: {str(exc)}",
        }

"""JSON transform tool: filter, select, sort, group, and limit a JSON array."""

from typing import Any, Dict, List


def json_transform(input_data: dict) -> dict:
    """Filter, select fields, sort, or group a JSON array.

    Parameters:
        data (list[dict]): Input array of objects.
        select_fields (list[str], optional): Fields to keep.
        filter_field (str, optional): Field to filter on.
        filter_value (any, optional): Value to match.
        filter_op (str, optional): Comparison operator. Default "eq".
            Supported: "eq", "ne", "gt", "lt", "gte", "lte", "contains", "in".
        sort_by (str, optional): Field to sort by.
        sort_desc (bool, optional): Descending sort, default false.
        group_by (str, optional): Field to group by.
        limit (int, optional): Max records to return.

    Returns:
        dict with data, count, grouped flag, and optional error.
    """
    try:
        data = input_data.get("data")
        if not isinstance(data, list):
            return {"data": [], "count": 0, "error": "Parameter 'data' is required and must be a list of dicts."}

        working: List[Dict[str, Any]] = list(data)

        # --- 1. Filter ---------------------------------------------------------
        filter_field = input_data.get("filter_field")
        filter_value = input_data.get("filter_value")
        filter_op = str(input_data.get("filter_op", "eq")).lower()

        valid_ops = {"eq", "ne", "gt", "lt", "gte", "lte", "contains", "in"}
        if filter_op not in valid_ops:
            return {"data": [], "count": 0, "error": f"Invalid filter_op '{filter_op}'. Must be one of {sorted(valid_ops)}."}

        if filter_field is not None:
            filtered: List[Dict[str, Any]] = []
            for record in working:
                val = record.get(filter_field)
                if _apply_op(val, filter_op, filter_value):
                    filtered.append(record)
            working = filtered

        # --- 2. Select fields --------------------------------------------------
        select_fields = input_data.get("select_fields")
        if isinstance(select_fields, list) and select_fields:
            working = [{k: rec.get(k) for k in select_fields} for rec in working]

        # --- 3. Sort -----------------------------------------------------------
        sort_by = input_data.get("sort_by")
        sort_desc = bool(input_data.get("sort_desc", False))

        if sort_by is not None:
            def sort_key(rec: dict) -> Any:
                v = rec.get(sort_by)
                # Put None values last regardless of direction
                if v is None:
                    return (1, "")
                return (0, v)

            try:
                working.sort(key=sort_key, reverse=sort_desc)
            except TypeError:
                # Fallback: stringify values for comparison when types are mixed
                working.sort(key=lambda r: str(r.get(sort_by, "")), reverse=sort_desc)

        # --- 4. Group ----------------------------------------------------------
        group_by = input_data.get("group_by")
        grouped = False

        if group_by is not None:
            groups: Dict[str, List[Dict[str, Any]]] = {}
            for rec in working:
                key = str(rec.get(group_by, "__none__"))
                groups.setdefault(key, []).append(rec)
            grouped = True

        # --- 5. Limit ----------------------------------------------------------
        limit = input_data.get("limit")

        if grouped and group_by is not None:
            if limit is not None:
                limit = int(limit)
                # Apply limit to each group
                groups = {k: v[:limit] for k, v in groups.items()}
            total = sum(len(v) for v in groups.values())
            return {"data": groups, "count": total, "grouped": True}

        if limit is not None:
            limit = int(limit)
            working = working[:limit]

        return {"data": working, "count": len(working)}

    except Exception as exc:
        return {"data": [], "count": 0, "error": f"Unexpected error: {str(exc)}"}


def _apply_op(val: Any, op: str, target: Any) -> bool:
    """Apply a comparison operation. Returns False on type errors instead of raising."""
    try:
        if op == "eq":
            return val == target
        if op == "ne":
            return val != target
        if op == "gt":
            return val > target
        if op == "lt":
            return val < target
        if op == "gte":
            return val >= target
        if op == "lte":
            return val <= target
        if op == "contains":
            if isinstance(val, str) and isinstance(target, str):
                return target in val
            if isinstance(val, list):
                return target in val
            return False
        if op == "in":
            if isinstance(target, (list, tuple, set)):
                return val in target
            return False
    except (TypeError, ValueError):
        return False
    return False

"""Deduplicate tool: remove duplicate entries from a list by specified fields."""

import hashlib
import json
from typing import Any, Dict, List


def deduplicate(input_data: dict) -> dict:
    """Remove duplicate entries from a list by specified fields.

    Parameters:
        data (list[dict]): Input data.
        fields (list[str], optional): Fields to check for duplicates. If empty, compare all fields.
        keep (str, optional): "first" or "last", default "first".

    Returns:
        dict with data, original_count, deduplicated_count, duplicates_removed, and optional error.
    """
    try:
        data = input_data.get("data")
        if not isinstance(data, list):
            return _error_result("Parameter 'data' is required and must be a list of dicts.")

        fields = input_data.get("fields")
        if fields is not None and not isinstance(fields, list):
            return _error_result("Parameter 'fields' must be a list of strings.")

        keep = str(input_data.get("keep", "first")).lower()
        if keep not in ("first", "last"):
            return _error_result("Parameter 'keep' must be 'first' or 'last'.")

        # Use all fields when fields is None or empty
        use_all = fields is None or len(fields) == 0

        original_count = len(data)

        if keep == "first":
            result = _deduplicate_first(data, fields, use_all)
        else:
            result = _deduplicate_last(data, fields, use_all)

        deduplicated_count = len(result)

        return {
            "data": result,
            "original_count": original_count,
            "deduplicated_count": deduplicated_count,
            "duplicates_removed": original_count - deduplicated_count,
        }

    except Exception as exc:
        return _error_result(f"Unexpected error: {str(exc)}")


def _record_hash(record: Any, fields: Any, use_all: bool) -> str:
    """Create a deterministic hash for the relevant parts of a record."""
    if not isinstance(record, dict):
        # For non-dict items, hash the JSON representation
        raw = json.dumps(record, sort_keys=True, default=str)
    elif use_all:
        raw = json.dumps(record, sort_keys=True, default=str)
    else:
        subset = {f: record.get(f) for f in fields}
        raw = json.dumps(subset, sort_keys=True, default=str)
    return hashlib.sha256(raw.encode("utf-8")).hexdigest()


def _deduplicate_first(data: List[Any], fields: Any, use_all: bool) -> List[Any]:
    """Keep the first occurrence of each unique record."""
    seen: Dict[str, bool] = {}
    result: List[Any] = []
    for record in data:
        h = _record_hash(record, fields, use_all)
        if h not in seen:
            seen[h] = True
            result.append(record)
    return result


def _deduplicate_last(data: List[Any], fields: Any, use_all: bool) -> List[Any]:
    """Keep the last occurrence of each unique record."""
    # Walk in reverse, keep first seen (which is actually last in original order),
    # then reverse the result to preserve relative ordering.
    seen: Dict[str, bool] = {}
    result: List[Any] = []
    for record in reversed(data):
        h = _record_hash(record, fields, use_all)
        if h not in seen:
            seen[h] = True
            result.append(record)
    result.reverse()
    return result


def _error_result(message: str) -> dict:
    """Return a standardised error response."""
    return {
        "data": [],
        "original_count": 0,
        "deduplicated_count": 0,
        "duplicates_removed": 0,
        "error": message,
    }

import textwrap


def _render_table(rows: list) -> str:
    """Render a list of dicts as an aligned markdown table."""
    if not rows or not isinstance(rows, list):
        return ""

    # Collect all column names preserving insertion order
    columns = []
    seen = set()
    for row in rows:
        if isinstance(row, dict):
            for key in row:
                if key not in seen:
                    columns.append(key)
                    seen.add(key)

    if not columns:
        return ""

    # Compute column widths (minimum 3 for the separator dashes)
    widths = {}
    for col in columns:
        widths[col] = max(len(str(col)), 3)
        for row in rows:
            if isinstance(row, dict):
                val = str(row.get(col, ""))
                widths[col] = max(widths[col], len(val))

    # Header
    header = "| " + " | ".join(str(col).ljust(widths[col]) for col in columns) + " |"
    separator = "| " + " | ".join("-" * widths[col] for col in columns) + " |"

    # Rows
    lines = [header, separator]
    for row in rows:
        if isinstance(row, dict):
            cells = []
            for col in columns:
                cells.append(str(row.get(col, "")).ljust(widths[col]))
            lines.append("| " + " | ".join(cells) + " |")

    return "\n".join(lines)


def _render_list(items: list) -> str:
    """Render a list of strings as markdown bullet points."""
    lines = []
    for item in items:
        lines.append(f"- {item}")
    return "\n".join(lines)


def _render_key_value(data: dict) -> str:
    """Render a dict as bold-key / value lines."""
    lines = []
    for key, value in data.items():
        lines.append(f"**{key}:** {value}")
    return "\n\n".join(lines)


def format_markdown_report(input_data: dict) -> dict:
    """Generate structured markdown from data (tables, headers, lists, sections).

    Parameters:
        title (str): Report title.
        sections (list[dict]): Report sections, each with heading, type, content.
        summary (str, optional): Summary text at top.

    Returns:
        dict with keys: markdown, char_count, section_count, error (optional).
    """
    try:
        if not isinstance(input_data, dict):
            return {"markdown": "", "char_count": 0, "section_count": 0, "error": "input_data must be a dict"}

        title = input_data.get("title")
        sections = input_data.get("sections")
        summary = input_data.get("summary")

        if not title:
            return {"markdown": "", "char_count": 0, "section_count": 0, "error": "'title' is required"}

        if not sections or not isinstance(sections, list):
            return {"markdown": "", "char_count": 0, "section_count": 0, "error": "'sections' must be a non-empty list"}

        parts = []

        # Title
        parts.append(f"# {title}")
        parts.append("")

        # Summary
        if summary:
            parts.append(str(summary))
            parts.append("")

        section_count = 0

        for section in sections:
            if not isinstance(section, dict):
                continue

            heading = section.get("heading", "Untitled Section")
            section_type = section.get("type", "text")
            content = section.get("content")

            parts.append(f"## {heading}")
            parts.append("")

            if content is None:
                parts.append("*No content provided.*")
                parts.append("")
                section_count += 1
                continue

            if section_type == "text":
                parts.append(str(content))

            elif section_type == "table":
                if isinstance(content, list):
                    table_md = _render_table(content)
                    if table_md:
                        parts.append(table_md)
                    else:
                        parts.append("*Empty table.*")
                else:
                    parts.append("*Table content must be a list of dicts.*")

            elif section_type == "list":
                if isinstance(content, list):
                    parts.append(_render_list(content))
                else:
                    parts.append(f"- {content}")

            elif section_type == "key_value":
                if isinstance(content, dict):
                    parts.append(_render_key_value(content))
                else:
                    parts.append("*Key-value content must be a dict.*")

            else:
                # Fallback: treat as text
                parts.append(str(content))

            parts.append("")
            section_count += 1

        markdown = "\n".join(parts).rstrip() + "\n"

        return {
            "markdown": markdown,
            "char_count": len(markdown),
            "section_count": section_count,
        }

    except Exception as exc:
        return {"markdown": "", "char_count": 0, "section_count": 0, "error": f"Unexpected error: {exc}"}
